pair E = (0,(sqrt(850)-6)/2);
pair G = (sqrt(850),(sqrt(850)+sqrt(100))/2);
dot("$E$",E,dir(180));
dot("$G$",G,dir(0));
draw(E--G);
pair P = extension(H,F,E,G);
dot("$P$",P,dir(60));
label("$w$", (H+E)/2,fontsize(15));
label("$x$", (E+F)/2,fontsize(15));
label("$y$", (G+F)/2,fontsize(15));
